) AS v(semester, subject_code, grade, body)
JOIN public.subjects s ON s.code = v.subject_code
WHERE NOT EXISTS (
  SELECT 1 FROM public.comment_bank cb
  WHERE cb.semester = v.semester
    AND cb.subject_id = s.id
    AND cb.body = v.body
);
